sealed class CoreException: kotlin.Exception() {
    
    class InvalidKey(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class EncryptionFailed(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class DecryptionFailed(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class InvalidData(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class StorageNotInitialized(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class StorageException(
        
        val `details`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class InvalidLink(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class FriendNotFound(
        ) : CoreException() {
        override val message
            get() = ""
    }
    
    class StaleLocation(
        ) : CoreException() {
        override val message
            get() = ""
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<CoreException> {
        override fun lift(error_buf: RustBuffer.ByValue): CoreException = FfiConverterTypeCoreError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeCoreError : FfiConverterRustBuffer<CoreException> {
    override fun read(buf: ByteBuffer): CoreException {
        

        return when(buf.getInt()) {
            1 -> CoreException.InvalidKey()
            2 -> CoreException.EncryptionFailed()
            3 -> CoreException.DecryptionFailed()
            4 -> CoreException.InvalidData()
            5 -> CoreException.StorageNotInitialized()
            6 -> CoreException.StorageException(
                FfiConverterString.read(buf),
                )
            7 -> CoreException.InvalidLink()
            8 -> CoreException.FriendNotFound()
            9 -> CoreException.StaleLocation()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CoreException): ULong {
        return when(value) {
            is CoreException.InvalidKey -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.EncryptionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.DecryptionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.InvalidData -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.StorageNotInitialized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.StorageException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is CoreException.InvalidLink -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.FriendNotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CoreException.StaleLocation -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: CoreException, buf: ByteBuffer) {
        when(value) {
            is CoreException.InvalidKey -> {
                buf.putInt(1)
                Unit
            }
            is CoreException.EncryptionFailed -> {
                buf.putInt(2)
                Unit
            }
            is CoreException.DecryptionFailed -> {
                buf.putInt(3)
                Unit
            }
            is CoreException.InvalidData -> {
                buf.putInt(4)
                Unit
            }
            is CoreException.StorageNotInitialized -> {
                buf.putInt(5)
                Unit
            }
            is CoreException.StorageException -> {
                buf.putInt(6)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is CoreException.InvalidLink -> {
                buf.putInt(7)
                Unit
            }
            is CoreException.FriendNotFound -> {
                buf.putInt(8)
                Unit
            }
            is CoreException.StaleLocation -> {
                buf.putInt(9)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




