        }
    }

    override fun allocationSize(value: List<Friend>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeFriend.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<Friend>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterTypeFriend.write(it, buf)
        }
    }
}




